-- Seed: expanded question-bank taxonomy v2 (generated from
-- docs/question-taxonomy-v1.csv + docs/essential-question-variants-v1.csv).
-- Idempotent: upserts by slug; never deletes or deactivates existing rows.
--
-- Levels: subjects -> topics (with strand grouping) -> question_types
-- (essential question types, with authoring metadata) -> question_variants.

insert into public.subjects (name, slug, description, sort_order)
values
  ('Reading', 'reading', null, 1),
  ('Mathematical Reasoning', 'mathematical-reasoning', null, 2),
  ('Thinking Skills', 'thinking-skills', null, 3),
  ('Writing', 'writing', null, 4)
on conflict (slug) do update
set name = excluded.name, is_active = true;

with topic_seed(subject_slug, name, slug, strand, sort_order) as (
