    ('mathematical-reasoning', 'Algebra', 'algebra', 'Patterns & Algebra', 13),
    ('mathematical-reasoning', 'Tables & Graphs', 'tables-graphs', 'Data', 14),
    ('mathematical-reasoning', 'Statistics', 'statistics', 'Data', 15),
    ('mathematical-reasoning', 'Probability', 'probability', 'Chance', 16),
