    ('writing', 'Persuasive & Discursive Writing', 'persuasive-discursive-writing', 'Written Expression', 2),
    ('writing', 'Informative Writing', 'informative-writing', 'Written Expression', 3),
    ('writing', 'Applied Writing', 'applied-writing', 'Written Expression', 4)
)
insert into public.topics (subject_id, name, slug, strand, sort_order)
select subjects.id, topic_seed.name, topic_seed.slug, topic_seed.strand, topic_seed.sort_order
from topic_seed
join public.subjects on subjects.slug = topic_seed.subject_slug
on conflict (subject_id, slug) do update
set
  name = excluded.name,
  strand = excluded.strand,
  is_active = true;

with type_seed(subject_slug, topic_slug, name, slug, description, common_trap, difficulty_min, difficulty_max, recommended_answer_format, assets_commonly_needed, sort_order) as (
  values
    ('reading', 'narrative-extracts', 'Literal comprehension', 'literal-comprehension', 'Tests retrieval of facts and details stated explicitly in the passage.', 'Students pick an option that sounds plausible instead of checking the exact wording of the text.', 1, 3, 'single_choice', false, 1),
    ('reading', 'narrative-extracts', 'Inference', 'inference', 'Tests drawing a conclusion from clues that are implied but never directly stated.', 'Students choose an answer that is true in general but not actually supported by the passage.', 2, 5, 'single_choice', false, 2),
    ('reading', 'narrative-extracts', 'Main idea', 'main-idea', 'Tests identifying the central point of a passage or paragraph rather than its details.', 'Students select a frequently mentioned detail instead of the idea that covers the whole text.', 2, 4, 'single_choice', false, 3),
    ('reading', 'narrative-extracts', 'Theme', 'theme', 'Tests recognising the underlying message or lesson the writer conveys through the story.', 'Students restate the plot instead of the broader idea the events illustrate.', 3, 5, 'single_choice', false, 4),
    ('reading', 'narrative-extracts', 'Vocabulary in context', 'vocabulary-in-context', 'Tests working out the meaning of a word or phrase as it is used in the passage.', 'Students choose the most common dictionary meaning instead of the meaning that fits the context.', 2, 4, 'single_choice', false, 5),
    ('reading', 'narrative-extracts', 'Tone and attitude', 'tone-and-attitude', 'Tests identifying the narrator''s or writer''s tone and attitude towards the subject.', 'Students confuse a character''s emotion with the tone of the narration itself.', 2, 5, 'single_choice', false, 6),
    ('reading', 'narrative-extracts', 'Language feature effect', 'language-feature-effect', 'Tests explaining why the writer used a technique such as simile or repetition and what effect it creates.', 'Students name the device correctly but choose a vague generic effect that does not fit this passage.', 3, 5, 'single_choice', false, 7),
    ('reading', 'narrative-extracts', 'Text structure', 'text-structure', 'Tests recognising how the passage is organised such as by contrast or by cause and effect.', 'Students describe what the text says rather than how it is arranged.', 2, 4, 'single_choice', false, 8),
    ('reading', 'narrative-extracts', 'Author purpose', 'author-purpose', 'Tests identifying why the author wrote the text such as to persuade or to entertain.', 'Students confuse the topic of the text with the author''s reason for writing it.', 2, 4, 'single_choice', false, 9),
    ('reading', 'narrative-extracts', 'Character motivation', 'character-motivation', 'Tests working out why a character acts or speaks the way they do.', 'Students choose what the character did rather than the reason behind the action.', 2, 4, 'single_choice', false, 10),
    ('reading', 'narrative-extracts', 'Character change', 'character-change', 'Tests tracking how a character''s feelings or views shift across the passage.', 'Students describe only the character''s final state and miss the shift from the beginning.', 2, 5, 'single_choice', false, 11),
    ('reading', 'narrative-extracts', 'Setting and atmosphere', 'setting-and-atmosphere', 'Tests identifying the mood created by the description of a place or time.', 'Students choose a literal detail about the location instead of the feeling it creates.', 2, 4, 'single_choice', false, 12),
    ('reading', 'narrative-extracts', 'Narrative perspective', 'narrative-perspective', 'Tests recognising who is telling the story and how that shapes what the reader knows.', 'Students confuse a first-person narrator with the author of the text.', 2, 4, 'single_choice', false, 13),
    ('reading', 'narrative-extracts', 'Sequencing', 'sequencing', 'Tests placing events from the passage in the order they actually happened.', 'Students use the order events are mentioned even when the text includes a flashback.', 1, 3, 'single_choice', false, 14),
    ('reading', 'narrative-extracts', 'Evidence matching', 'evidence-matching', 'Tests selecting the quotation or line that best supports a given statement.', 'Students pick a quote on the same topic that does not actually prove the statement.', 2, 4, 'single_choice', false, 15),
    ('reading', 'poetry', 'Poetry imagery', 'poetry-imagery', 'Tests interpreting the pictures a poem creates through sensory language.', 'Students read figurative lines literally and choose a surface-level meaning.', 3, 5, 'single_choice', false, 16),
    ('reading', 'poetry', 'Poetry tone', 'poetry-tone', 'Tests identifying the speaker''s mood or attitude across a poem or stanza.', 'Students judge tone from one striking word instead of the poem as a whole.', 3, 5, 'single_choice', false, 17),
    ('reading', 'poetry', 'Symbolism', 'symbolism', 'Tests recognising when an object or image in a poem stands for a bigger idea.', 'Students choose the literal object rather than the idea it represents.', 3, 5, 'single_choice', false, 18),
    ('reading', 'paired-extracts', 'Paired extract comparison', 'paired-extract-comparison', 'Tests comparing ideas or attitudes or techniques across two related extracts.', 'Students answer correctly about one text but ignore what the other text says.', 3, 5, 'single_choice', false, 19),
    ('reading', 'information-texts', 'Information text interpretation', 'information-text-interpretation', 'Tests locating and interpreting information in factual texts such as articles and notices.', 'Students stop at the first matching keyword instead of reading the full condition or exception.', 2, 4, 'single_choice', false, 20),
    ('reading', 'cloze-passage', 'Cloze passage grammar', 'cloze-passage-grammar', 'Tests choosing the word or phrase that fits the grammar of a gap in a passage.', 'Students pick a word that fits the sentence alone but breaks tense or agreement with the surrounding text.', 2, 4, 'single_choice', false, 21),
    ('reading', 'cloze-passage', 'Cloze passage vocabulary', 'cloze-passage-vocabulary', 'Tests choosing the word that best fits the meaning and register of a gap in a passage.', 'Students choose a near-synonym that clashes with the tone or collocations around the gap.', 2, 5, 'single_choice', false, 22),
    ('mathematical-reasoning', 'arithmetic', 'Arithmetic operations', 'arithmetic-operations', 'Tests accurate addition subtraction multiplication and division with whole numbers.', 'Students misapply order of operations or make regrouping errors under time pressure.', 1, 3, 'single_choice', false, 1),
    ('mathematical-reasoning', 'arithmetic', 'Place value', 'place-value', 'Tests understanding the value of digits and comparing or rounding large numbers.', 'Students confuse the digit itself with its value in that position.', 1, 3, 'single_choice', false, 2),
