    ('thinking-skills', 'argument-analysis', 'Identify assumption', 'identify-assumption', 'Tests finding the unstated idea the argument needs in order to work.', 'Students choose a stated reason instead of the missing link that is never said.', 3, 5, 'single_choice', false, 5),
