    ('thinking-skills', 'mathematical-analysis', 'Pattern recognition', 'pattern-recognition', 'Tests spotting the numeric rule linking terms in an unfamiliar sequence or array.', 'Students match the first two terms to a rule and never check it on the rest.', 2, 5, 'single_choice', false, 19),
    ('thinking-skills', 'mathematical-analysis', 'Rule deduction', 'rule-deduction', 'Tests working out the hidden operation a machine or code applies to inputs.', 'Students find a rule that fits one example and assume it fits all of them.', 3, 5, 'single_choice', false, 20),
