insert into public.question_types (subject_id, topic_id, name, slug, description, common_trap, difficulty_min, difficulty_max, recommended_answer_format, assets_commonly_needed, sort_order)
select
  subjects.id,
  topics.id,
  type_seed.name,
  type_seed.slug,
  type_seed.description,
  type_seed.common_trap,
  type_seed.difficulty_min,
  type_seed.difficulty_max,
  type_seed.recommended_answer_format,
  type_seed.assets_commonly_needed,
  type_seed.sort_order
from type_seed
join public.subjects on subjects.slug = type_seed.subject_slug
left join public.topics on topics.subject_id = subjects.id and topics.slug = type_seed.topic_slug
on conflict (subject_id, slug) do update
set
  topic_id = excluded.topic_id,
  name = excluded.name,
  description = excluded.description,
  common_trap = excluded.common_trap,
  difficulty_min = excluded.difficulty_min,
  difficulty_max = excluded.difficulty_max,
  recommended_answer_format = excluded.recommended_answer_format,
  assets_commonly_needed = excluded.assets_commonly_needed,
  sort_order = excluded.sort_order,
  is_active = true;

