insert into public.question_variants (question_type_id, name, slug, description, sort_order)
select question_types.id, variant_seed.name, variant_seed.slug, variant_seed.description, variant_seed.sort_order
from variant_seed
join public.subjects on subjects.slug = variant_seed.subject_slug
join public.question_types
  on question_types.subject_id = subjects.id
  and question_types.slug = variant_seed.type_slug
on conflict (question_type_id, slug) do update
set
  name = excluded.name,
  description = excluded.description,
  sort_order = excluded.sort_order,
  is_active = true;
